        env.storage().instance().get(&Symbol::new(&env, "val")).unwrap_or(0)
    }
}

use soroban_sdk::{contract, contractimpl, Address, Env, Bytes, symbol_short};

#[contractimpl]
impl EventContract {
    pub fn transfer(env: Env, from: Address, to: Address, amount: i128) {
        env.events().publish((symbol_short!("transfer"), from, to, amount, amount), ());
        env.events().publish((symbol_short!("log"), Bytes::from_slice(&env, &[1])), ());
        env.events().publish((symbol_short!("ok"), from), ());
    }
}
